function getLLMConfig() {
  const base = { provider: "anthropic", model: MODEL, apiKey: "", geminiKey: "", geminiModel: GEMINI_MODEL };
  if (typeof window !== "undefined" && window.__LLM_CONFIG) {
    const cfg = { ...base, ...window.__LLM_CONFIG };
    if (cfg.apiKey && !cfg.provider) cfg.provider = guessProviderFromKey(cfg.apiKey);
    return cfg;
  }
  try {
    const raw = localStorage.getItem("hc:llm-config");
    if (raw) {
      const cfg = { ...base, ...JSON.parse(raw) };
      if (cfg.apiKey && !cfg.provider) cfg.provider = guessProviderFromKey(cfg.apiKey);
      return cfg;
    }
    const legacy = localStorage.getItem("anthropic-api-key");
    if (legacy) {
      const provider = guessProviderFromKey(legacy);
      return {
        ...base,
        provider,
        apiKey: legacy,
        model: provider === "deepseek" ? LLM_DEFAULTS.deepseek.model : MODEL,
      };
    }
  } catch (_) {}
  return base;
}

function saveLLMConfig(patch) {
  const next = { ...getLLMConfig(), ...patch };
  try { localStorage.setItem("hc:llm-config", JSON.stringify(next)); } catch (_) {}
  if (typeof window !== "undefined") window.__LLM_CONFIG = next;
  return next;
}

function guessProviderFromKey(key) {
  if (!key) return "anthropic";
  if (key.startsWith("sk-ant-")) return "anthropic";
  return "deepseek";
}

function resolveProvider(cfg) {
  if (cfg.apiKey?.startsWith("sk-ant-")) return "anthropic";
  if (cfg.apiKey?.startsWith("sk-")) return "deepseek";
  return cfg.provider || "anthropic";
}

// 校验模型名：空、或写成了 provider 名（anthropic/deepseek/claude/Anthropic 等）一律回退到默认
function resolveModel(cfg, provider) {
  const fallback = provider === "deepseek" ? LLM_DEFAULTS.deepseek.model : LLM_DEFAULTS.anthropic.model;
  const m = (cfg.model || "").trim();
  if (!m) return fallback;
  // 必须是较完整的模型名；"claude"/"anthropic"/"deepseek" 这种残缺名一律回退默认
  const looksValid = provider === "deepseek"
    ? /^deepseek-\w/i.test(m)
    : /^claude-[\w]/i.test(m) && m.length >= 12;
  return looksValid ? m : fallback;
}

function useLLMProxy() {
  if (typeof window === "undefined") return false;
  const h = window.location.hostname;
  return h === "localhost" || h === "127.0.0.1";
}

async function callLLMViaProxy(cfg, provider, userContent, maxTokens) {
  const res = await fetch("/api/llm-proxy", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      provider,
      apiKey: cfg.apiKey,
      model: resolveModel(cfg, provider),
      messages: [{ role: "user", content: userContent }],
      max_tokens: maxTokens,
    }),
  });
  let json;
  try { json = await res.json(); } catch (_) {
    throw new Error(`AI 代理返回异常 (HTTP ${res.status})。请用 python3 preview/serve.py 启动本地服务。`);
  }
  if (!res.ok || json.error) {
    const msg = typeof json.error === "string" ? json.error : json.error?.message || json.message;
    throw new Error(msg || `AI 代理 HTTP ${res.status}`);
  }
  return json.text || "";
}

// 云端多用户模式：只带登录令牌调后端代理，key 全在服务器
async function callAuthProxy(payload) {
  const token = (typeof window !== "undefined" && window.__getToken) ? await window.__getToken() : null;
  if (!token) throw new Error("请先登录");
  const res = await fetch("/api/llm-proxy", {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
    body: JSON.stringify(payload),
  });
  let json;
  try { json = await res.json(); } catch (_) { throw new Error(`服务返回异常 (HTTP ${res.status})`); }
  if (!res.ok || json.error) {
    const msg = typeof json.error === "string" ? json.error : json.error?.message || json.message;
    throw new Error(msg || `服务 HTTP ${res.status}`);
  }
  return json.text || "";
}

const useAuthProxy = () => typeof window !== "undefined" && window.__AUTH_PROXY === true;

async function callLLM(userContent, maxTokens = 2000) {
  if (useAuthProxy()) {
    return callAuthProxy({ task: "text", messages: [{ role: "user", content: userContent }], max_tokens: maxTokens });
  }
  const cfg = getLLMConfig();
  const provider = resolveProvider(cfg);
  if (!cfg.apiKey) {
    throw new Error(provider === "deepseek"
      ? "请先在设置填入 DeepSeek API Key（sk- 开头）"
      : "请先在设置填入 Anthropic API Key（sk-ant- 开头）");
  }
  if (provider === "anthropic" && !cfg.apiKey.startsWith("sk-ant-")) {
    throw new Error("Anthropic 需要 sk-ant- 开头的 Key。若用 DeepSeek，请到设置切换提供商。");
  }

  // 本地预览统一走 serve.py 代理，避免浏览器直连 Anthropic 的各种失败
  if (useLLMProxy() || provider === "deepseek") {
    return callLLMViaProxy(cfg, provider, userContent, maxTokens);
  }

  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: resolveModel(cfg, "anthropic"),
      max_tokens: maxTokens,
      messages: [{ role: "user", content: userContent }],
    }),
  });
  let json;
  try { json = await res.json(); } catch (_) { throw new Error(`Anthropic 返回异常 (HTTP ${res.status})。请检查 API Key 是否为 sk-ant- 开头。`); }
  if (!res.ok || json.error) throw new Error(json.error?.message || json.error?.type || `Anthropic HTTP ${res.status}`);
  return (json.content || []).filter((b) => b.type === "text").map((b) => b.text).join("");
}

// ── 图片识别（Gemini）────────────────────────
// 把图片缩放压缩成 base64，控制体积（识别食物 1024px 足够）
function fileToImagePart(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("读取图片失败"));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error("解析图片失败"));
      img.onload = () => {
        const max = 1024;
        let { width: w, height: h } = img;
        if (w > max || h > max) {
          const r = Math.min(max / w, max / h);
          w = Math.round(w * r); h = Math.round(h * r);
        }
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        canvas.getContext("2d").drawImage(img, 0, 0, w, h);
        const dataUrl = canvas.toDataURL("image/jpeg", 0.82);
        resolve({ dataUrl, media_type: "image/jpeg", data: dataUrl.split(",")[1] });
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

async function callVision(images, userText, maxTokens = 1200) {
  const content = VISION_PROMPT + (userText ? `\n\n用户补充说明：${userText}` : "");
  if (useAuthProxy()) {
    return callAuthProxy({
      task: "vision",
      images: images.map((im) => ({ media_type: im.media_type, data: im.data })),
      prompt: content,
      max_tokens: maxTokens,
    });
  }
  const cfg = getLLMConfig();
  const key = (cfg.geminiKey || "").trim();
  if (!key) throw new Error("请先在设置填入 Gemini API Key（用于图片识别）");
  const model = (cfg.geminiModel || "").trim() || GEMINI_MODEL;
  const payload = {
    provider: "gemini",
    apiKey: key,
    model,
    images: images.map((im) => ({ media_type: im.media_type, data: im.data })),
    messages: [{ role: "user", content }],
    max_tokens: maxTokens,
  };

  if (useLLMProxy()) {
    const res = await fetch("/api/llm-proxy", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    let json;
    try { json = await res.json(); } catch (_) {
      throw new Error(`AI 代理返回异常 (HTTP ${res.status})。请用 python3 preview/serve.py 启动本地服务。`);
    }
    if (!res.ok || json.error) {
      const msg = typeof json.error === "string" ? json.error : json.error?.message || json.message;
      throw new Error(msg || `Gemini 代理 HTTP ${res.status}`);
    }
    return json.text || "";
  }

  // 远程托管时浏览器直连 Gemini
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent`;
  const parts = [
    ...images.map((im) => ({ inline_data: { mime_type: im.media_type, data: im.data } })),
    { text: content },
  ];
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json", "x-goog-api-key": key },
    body: JSON.stringify({ contents: [{ parts }], generationConfig: { maxOutputTokens: maxTokens, temperature: 0.2 } }),
  });
  let json;
  try { json = await res.json(); } catch (_) { throw new Error(`Gemini 返回异常 (HTTP ${res.status})`); }
  if (!res.ok || json.error) throw new Error(json.error?.message || `Gemini HTTP ${res.status}`);
  const cand = (json.candidates || [])[0];
  return (cand?.content?.parts || []).map((p) => p.text || "").join("");
}

function formatAIError(err) {
  const msg = (err && err.message) ? String(err.message) : String(err || "未知错误");
  if (/llm-proxy|serve\.py|404/.test(msg)) {
    return "DeepSeek 需要本地代理：在项目目录运行 python3 preview/serve.py，然后打开 http://127.0.0.1:8765/preview/index.html";
  }
  if (/401|403|authentication|invalid.*key|api_key/i.test(msg)) {
    return `API Key 无效或与提供商不匹配：${msg}。Anthropic 用 sk-ant-；DeepSeek 用 sk- 并在设置里选 DeepSeek。`;
  }
  if (/Failed to fetch|NetworkError|Load failed/i.test(msg)) {
    return `网络请求失败：${msg}。若用 DeepSeek，请确认已用 serve.py 启动；若用 Anthropic，请确认 Key 有效。`;
  }
  if (/not_found|model.*invalid|does not exist/i.test(msg)) {
    return `模型名称无效或无权限：${msg}。Anthropic 可试 claude-sonnet-4-5-20250929（你的 Key 已验证可用）。`;
  }
  return `AI 调用失败：${msg}`;
}

// ── 日期工具 ───────────────────────────────
const iso = (d) =>
  `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(
    d.getDate()
  ).padStart(2, "0")}`;
const TODAY = iso(new Date());

// 把周日=0 转成周一=0
const mondayIndex = (jsDay) => (jsDay + 6) % 7;

// 从「补记 2026-06-10」这类话里识别目标日期
function inferBackfillDay(text, fallback) {
  if (!text) return fallback;
  const backfill = /补记|补录|补填|回填/.test(text);
  const isoM = text.match(/(\d{4}-\d{2}-\d{2})/);
  if (isoM && (backfill || isoM[1] !== TODAY)) return isoM[1];
  const cnM = text.match(/(\d{1,2})\s*月\s*(\d{1,2})\s*日/);
  if (cnM && backfill) {
    const y = new Date().getFullYear();
    return `${y}-${String(+cnM[1]).padStart(2, "0")}-${String(+cnM[2]).padStart(2, "0")}`;
  }
  return fallback;
}

// 从 AI 原始回复里抠 JSON（容忍 markdown 代码块）
function parseAIJson(raw) {
  if (!raw) throw new Error("empty");
  let s = String(raw).trim().replace(/^```(?:json)?\s*/i, "").replace(/\s*```\s*$/, "");
  const a = s.indexOf("{"), b = s.lastIndexOf("}");
  if (a === -1 || b === -1) throw new Error("no json");
  return JSON.parse(s.slice(a, b + 1));
}

// 用户是在陈述吃了/练了，而不是在提问
function looksLikeLog(text) {
  if (!text) return false;
  if (/[？?]|吗[。！]?$|行不行|可不可以|能不能|建议|应该吃/.test(text)) return false;
  return /(?:吃了|喝了|跑了|练了|做了|训练|运动|有氧|跑步|爬坡|早餐|早上|午饭|晚饭|加餐|\d+\s*kcal|\d+\s*大卡|\d+\s*卡\b|一个.*蛋|水煮蛋)/i.test(text);
}

// 从「早上8点半」这类话提取 HH:MM
function timeFromText(text) {
  if (!text) return null;
  const half = text.match(/(\d{1,2})\s*点半/);
  if (half) return `${String(+half[1]).padStart(2, "0")}:30`;
  const hm = text.match(/(\d{1,2})\s*[点:：]\s*(\d{1,2})\s*分?/);
  if (hm) return `${String(+hm[1]).padStart(2, "0")}:${String(+hm[2]).padStart(2, "0")}`;
  if (/早上|清晨|早晨/.test(text)) return "08:00";
  if (/中午|午饭/.test(text)) return "12:00";
  if (/下午/.test(text)) return "15:00";
  if (/晚上|晚饭/.test(text)) return "19:00";
  return null;
}

function applyTimesFromText(items, text, isFood) {
  const t = timeFromText(text);
  if (!t) return items;
  return items.map((it) => ({ ...it, time: it.time || t, ...(isFood ? {} : { kind: it.kind || "cardio" }) }));
}

// API 全挂时的离线兜底：解析句子里写明的 kcal 和常见食物
function parseLogLocally(text) {
  const foods = [], exercises = [];
  const parts = text.split(/然后|；|;/).map((s) => s.trim()).filter(Boolean);
  const chunks = parts.length > 1 ? parts : [text];
  for (const part of chunks) {
    const t = timeFromText(part) || timeFromText(text);
    let m = part.match(/(\d+)\s*kcal(?:ral|的)?\s*(.+?(?:训练|有氧|运动|跑步|爬坡)[^，,]*)/i);
    if (m) {
      exercises.push({ name: m[2].replace(/^[的\s]+/, "").trim(), burn: +m[1], kind: "cardio", ...(t ? { time: t } : {}) });
      continue;
    }
    m = part.match(/(?:做了|练了)\s*(\d+)\s*kcal(?:的)?\s*(.+)/i);
    if (m && /训练|有氧|运动|跑步|爬坡/.test(m[2])) {
      exercises.push({ name: m[2].trim(), burn: +m[1], kind: "cardio", ...(t ? { time: t } : {}) });
      continue;
    }
    m = part.match(/(?:吃了|吃了一个?|喝了)?(.+?)\s*(\d+)\s*kcal/i);
    if (m && !/训练|有氧|运动|跑步|爬坡/.test(m[1])) {
      const name = m[1].replace(/^(了|一个|一份)/, "").trim() || "食物";
      const kcal = +m[2];
      const isEgg = /蛋/.test(name);
      foods.push({
        name, kcal,
        protein: isEgg ? 6 : Math.round(kcal * 0.12),
        carbs: isEgg ? 0.5 : Math.round(kcal * 0.55),
        fat: isEgg ? 5 : Math.round(kcal * 0.28),
        fiber: 0,
        nutrients: isEgg ? "蛋白质" : "",
        ...(t ? { time: t } : {}),
      });
      continue;
    }
    m = part.match(/(?:早上|中午|晚上|早|午|晚)?(?:吃了|喝了)\s*(.+)/);
    if (m) {
      const name = m[1].trim();
      let kcal = 50;
      if (/哈密瓜|蜜瓜/.test(name)) {
        const n = name.match(/(\d+)\s*块/);
        kcal = n ? Math.round(+n[1] * 4) : 40;
      }
      const mealTime = /中午|午饭/.test(part) ? "12:00" : /早上|早晨/.test(part) ? "08:00" : /晚上|晚饭/.test(part) ? "19:00" : t;
      foods.push({ name, kcal, protein: 1, carbs: Math.round(kcal * 0.85), fat: 0, fiber: 1, nutrients: "维C、钾", ...(mealTime ? { time: mealTime } : {}) });
    }
  }
  if (!foods.length && !exercises.length) return null;
  return { foods, exercises, reply: "记好啦～（AI 不可用，已用离线规则估算）" };
}

