// 把种子数据里的内置历史合并进本地存档：
// - 某天还没有 entries → 填入 seed
// - seedRevision 升级 → 强制刷新 seed 里预置的补记天（保留该天 chat）
function mergeSeedDays(loaded) {
  const seed = seedData();
  const next = { ...loaded, days: { ...(loaded.days || {}) } };
  let changed = false;
  const storedRev = loaded.seedRevision || 0;
  const forceSeed = storedRev < SEED_REVISION;
  Object.keys(seed.days).forEach((key) => {
    const cur = next.days[key];
    const hasEntries = cur && Array.isArray(cur.entries) && cur.entries.length > 0;
    if (forceSeed || !hasEntries) {
      const chat = cur?.chat;
      next.days[key] = recompute(JSON.parse(JSON.stringify(seed.days[key])));
      if (chat?.length) next.days[key].chat = chat;
      changed = true;
    }
  });
  if (next.seedRevision !== SEED_REVISION) {
    next.seedRevision = SEED_REVISION;
    changed = true;
  }
  return { next, changed };
}

// 全新账号的空白数据：无示例历史、无经期、目标从今天起算
function blankData() {
  return {
    version: DATA_VERSION,
    seedRevision: SEED_REVISION,
    profile: PROFILE_DEFAULT,
    periods: [],
    goal: { targetKg: 4, durationDays: 90, startDate: TODAY },
    days: {},
  };
}

// opts.seed=false 时不灌入内置示例（多用户云端：每个账号独立、干净起步）
function hydrateData(raw, opts = {}) {
  const seed = opts.seed !== false;
  const profile = { ...PROFILE_DEFAULT, ...(raw.profile || {}) };
  const days = raw.days || {};
  if (!seed) {
    const periods = raw.periods || [];
    const goal = raw.goal || { targetKg: 4, durationDays: 90, startDate: TODAY };
    const base = { ...raw, profile, days, periods, goal, version: DATA_VERSION, seedRevision: SEED_REVISION };
    Object.keys(base.days).forEach((k) => { base.days[k] = recompute(base.days[k]); });
    return { data: base, changed: (raw.version || 0) < DATA_VERSION };
  }
  const periods = (raw.periods && raw.periods.length) ? raw.periods : ["2026-06-06"];
  const goal = raw.goal || { targetKg: 4, durationDays: 90, startDate: "2026-06-06" };
  const base = { ...raw, profile, days, periods, goal, version: DATA_VERSION };
  const { next, changed } = mergeSeedDays(base);
  Object.keys(next.days).forEach((k) => { next.days[k] = recompute(next.days[k]); });
  return { data: next, changed: changed || (raw.version || 0) < DATA_VERSION };
}

// 去掉 AI 回复里的 markdown 记号，聊天里只显示纯文本
function stripMd(s) {
  if (!s) return s;
  return String(s)
    .replace(/\*\*(.*?)\*\*/g, "$1")
    .replace(/__(.*?)__/g, "$1")
    .replace(/\*(.*?)\*/g, "$1")
    .replace(/`([^`]*)`/g, "$1")
    .replace(/^#{1,6}\s*/gm, "")
    .replace(/^\s*[-•]\s+/gm, "· ")
    .trim();
}

// ── 累加一天的总量 ───────────────────────────────
const round2 = (n) => Math.round((Number(n) || 0) * 100) / 100;

// 把 "6g"、"60kcal" 之类的字符串安全转成数字
const num = (v) => {
  if (typeof v === "number") return v;
  const m = String(v ?? "").match(/-?\d+(\.\d+)?/);
  return m ? parseFloat(m[0]) : 0;
};

function recompute(day) {
  let intake = 0, protein = 0, carbs = 0, fat = 0, fiber = 0, burn = 0;
  for (const e of day.entries) {
    for (const f of e.foods || []) {
      intake += num(f.kcal); protein += num(f.protein);
      carbs += num(f.carbs); fat += num(f.fat); fiber += num(f.fiber);
    }
    for (const x of e.exercises || []) burn += num(x.burn);
  }
  return { ...day, intake: round2(intake), protein: round2(protein), carbs: round2(carbs), fat: round2(fat), fiber: round2(fiber), burn: round2(burn) };
}

// 规范化 AI 返回的条目：把数值字段统一成 number
function normFood(f) {
  return { ...f, kcal: num(f.kcal), protein: num(f.protein), carbs: num(f.carbs), fat: num(f.fat), fiber: num(f.fiber), ...(f.gi != null ? { gi: num(f.gi) } : {}) };
}
function normExercise(x) {
  return { ...x, burn: num(x.burn) };
}

// 收集某天食物里的营养成分标签（清洗掉句子/“注意：”等噪声，只留简短成分名）
function vitaminsOf(day) {
  const set = [];
  (day?.entries || []).forEach((e) =>
    (e.foods || []).forEach((f) => {
      if (!f.nutrients) return;
      String(f.nutrients).split(/[、,，/／;；\s]+/).forEach((v) => {
        let t = v.trim().replace(/^注意[:：]?/, "").replace(/[（(].*?[)）]/g, "").trim();
        if (!t) return;
        if (t.length > 6) return;                       // 太长多半是句子
        if (/[：:（）()]/.test(t)) return;               // 含句子标点
        if (/注意|若|需|额外|计入|极低|建议|不要|过量|每/.test(t)) return;
        if (!set.includes(t)) set.push(t);
      });
    })
  );
  return set;
}

// 需要注意/控制的成分（摄入过量或最好少吃）
const CAUTION_KEYS = ["糖", "添加糖", "精制糖", "酒精", "饱和脂肪", "反式脂肪", "钠", "盐", "胆固醇", "咖啡因", "嘌呤", "果葡糖浆"];
function nutrientKind(name) {
  return CAUTION_KEYS.some((k) => name.includes(k)) ? "caution" : "good";
}

// 找出某项宏量（fat/carbs…）贡献最大的食物
function topContributor(day, key) {
  let best = null;
  (day?.entries || []).forEach((e) =>
    (e.foods || []).forEach((f) => {
      const v = f[key] || 0;
      if (v > 0 && (!best || v > best.value)) best = { name: f.name, value: Math.round(v) };
    })
  );
  return best;
}

// ── 血糖（升糖）模型 ───────────────────────────────
// 没有 AI 给 GI 时的粗略回退：纤维占比越高，GI 越低
function estGI(f) {
  const c = f.carbs || 0;
  if (c <= 0) return 0;
  const fr = (f.fiber || 0) / c;
  if (fr > 0.2) return 35;
  if (fr > 0.1) return 50;
  return 68;
}
function foodGI(f) { return (f.gi != null && f.gi > 0) ? f.gi : estGI(f); }
function foodGL(f) { return (foodGI(f) / 100) * (f.carbs || 0); } // 血糖负荷
// 削峰：同一食物的纤维/蛋白/脂肪会压低、推后血糖峰
function foodPeak(f) {
  const gl = foodGL(f);
  const damp = 1 / (1 + (f.fiber || 0) * 0.5 + (f.protein || 0) * 0.08 + (f.fat || 0) * 0.04);
  return gl * damp;
}
function spikeWord(peak) { return peak >= 16 ? "高" : peak >= 9 ? "中" : "低"; }
// 升糖判定用「血糖负荷 GL」国际标准：GL≤10 低 · 11–19 中 · ≥20 高
function glWord(gl) { return gl >= 20 ? "高" : gl >= 11 ? "中" : "低"; }
function glColor(gl) { return gl >= 20 ? "#C8694E" : gl >= 11 ? "#B26A2E" : C.accentDark; }
function foodMinutes(f, ts) {
  if (f.time && /^\d{1,2}:\d{2}$/.test(f.time)) {
    const [h, m] = f.time.split(":").map(Number);
    return h * 60 + m;
  }
  const d = new Date(ts);
  return d.getHours() * 60 + d.getMinutes();
}

// 模块 B · 肌肉海绵引擎：当天有大强度训练 → 胰岛素敏感度↑ → 高糖冲击自动降级
const STRENGTH_RE = /(力量|训练|下拉|划船|深蹲|卧推|硬拉|推举|弯举|引体|臀推|背|腿|胸|肩|二头|三头)/;
const SPORT_RE = /(网球|篮球|足球|羽毛球|搏击|拳击|攀岩|爬山|HIIT|冲刺|跳绳)/;
function exKind(x) {
  if (x.kind) return x.kind;
  if (STRENGTH_RE.test(x.name || "")) return "strength";
  if (SPORT_RE.test(x.name || "")) return "sport";
  return "cardio";
}
function spongeOf(day) {
  const exs = [];
  (day?.entries || []).forEach((e) => (e.exercises || []).forEach((x) => exs.push({ ...x, min: foodMinutes(x, e.ts) })));
  if (!exs.length) return null;
  const totalBurn = exs.reduce((s, x) => s + (x.burn || 0), 0);
  const hasStrength = exs.some((x) => exKind(x) === "strength");
  const hasSport = exs.some((x) => exKind(x) === "sport");
  const intense = totalBurn >= 250 || hasStrength || hasSport;
  if (!intense) return null;
  // 海绵强度 0..1：结合消耗量与是否含力量/球类
  const burn01 = Math.max(0, Math.min(1, totalBurn / 600));
  const strength01 = Math.max(burn01, hasStrength ? 0.8 : 0, hasSport ? 0.65 : 0);
  const mult = 1 - 0.38 * strength01; // 峰值最多压低约 38%
  const reduction = Math.round((1 - mult) * 100);
  // 取最有代表性的训练名作为文案
  const names = exs.slice().sort((a, b) => (b.burn || 0) - (a.burn || 0)).map((x) => x.name);
  const since = Math.min(...exs.map((x) => x.min));
  return { mult, reduction, totalBurn, names, hasStrength, hasSport, since };
}

// 当天血糖响应曲线：饮食推高、运动下探，sponge 修正
function glucoseSeries(day) {
  const sponge = spongeOf(day);
  const meals = [], exers = [];
  (day?.entries || []).forEach((e) => {
    (e.foods || []).forEach((f) => {
      const rawPeak = foodPeak(f);
      if (rawPeak <= 0.3) return;
      const min = foodMinutes(f, e.ts);
      let mult = 1;
      if (sponge) mult = min >= sponge.since ? sponge.mult : 1 - (1 - sponge.mult) * 0.5;
      meals.push({ name: f.name, min, gi: foodGI(f), gl: foodGL(f), rawPeak, peak: rawPeak * mult, damped: mult < 0.98 });
    });
    (e.exercises || []).forEach((x) => {
      const burn = x.burn || 0;
      if (burn <= 0) return;
      exers.push({ name: x.name, min: foodMinutes(x, e.ts), amp: Math.min(16, burn / 38) });
    });
  });
  meals.sort((a, b) => a.min - b.min);
  const start = 6 * 60, end = 24 * 60, step = 10;
  const ptsRaw = [], ptsAdj = [];
  for (let t = start; t <= end; t += step) {
    let mr = 0, ma = 0, dip = 0;
    meals.forEach((m) => {
      const g = Math.exp(-((t - (m.min + 45)) ** 2) / (2 * 55 * 55));
      mr += m.rawPeak * g;
      ma += m.peak * g;
    });
    exers.forEach((x) => {
      const g = Math.exp(-((t - (x.min + 20)) ** 2) / (2 * 70 * 70));
      dip += x.amp * g;
    });
    ptsRaw.push({ t, v: mr });          // 对照：只有饮食、没有运动/修正
    ptsAdj.push({ t, v: ma - dip });    // 实际：含敏感度修正 + 运动消耗
  }
  const vmax = Math.max(0.001, ...ptsRaw.map((p) => p.v), ...ptsAdj.map((p) => p.v));
  const vmin = Math.min(0, ...ptsAdj.map((p) => p.v));
  return { ptsRaw, ptsAdj, meals, exers, vmax, vmin, sponge };
}
function glucoseStability(day) {
  const { meals } = glucoseSeries(day);
  if (!meals.length) return null;
  const maxGL = Math.max(0, ...meals.map((m) => m.gl));
  const bigSpikes = meals.filter((m) => m.gl >= 20).length;
  let level;
  if (maxGL >= 25 || bigSpikes >= 2) level = "起伏较大";
  else if (maxGL >= 11) level = "略有波动";
  else level = "较平稳";
  return { level, maxGL, bigSpikes, meals };
}

// 模块 A · 神仙搭配削峰方案：高升糖/纯碳水且缓冲不足 → 给可执行的“减速带”建议
function bufferHacks(day) {
  const out = [];
  (day?.entries || []).forEach((e) => {
    const foods = e.foods || [];
    foods.forEach((f) => {
      if (foodGI(f) < 58 || (f.carbs || 0) < 15) return; // 只针对高 GI 且有实质碳水
      const min = foodMinutes(f, e.ts);
      const inWork = (min < 12 * 60) || (min >= 13 * 60 && min < 18 * 60);
      // 同餐里的“缓冲”：其他食物的蛋白/脂肪/纤维
      const others = foods.filter((o) => o !== f);
      const buffer = others.reduce((s, o) => s + (o.protein || 0) + (o.fat || 0) + (o.fiber || 0) * 2, 0) + (f.fiber || 0);
      if (buffer >= 24) return; // 已经搭配得不错，不打扰
      const hasVegProtein = others.some((o) => (o.fiber || 0) >= 2 || (o.protein || 0) >= 8);
      if (hasVegProtein) {
        out.push({ kind: "顺序", inWork, food: f.name, text: `检测到${f.name}与同餐的蔬菜/蛋白。先吃菜和蛋白、最后吃${f.name}——这个顺序能压低约 30% 的${inWork ? "工作时段" : "餐后"}血糖峰，少犯困。` });
      } else {
        out.push({ kind: "搭配", inWork, food: f.name, text: `${f.name}基本是纯碳水。下次先来杯无糖豆浆或几颗坚果，用蛋白质+脂肪当“减速带”，给血糖升速踩一脚刹车。` });
      }
    });
  });
  // 工作时段优先，去重，最多 2 条
  out.sort((a, b) => (b.inWork ? 1 : 0) - (a.inWork ? 1 : 0));
  const seen = new Set();
  return out.filter((h) => (seen.has(h.food) ? false : (seen.add(h.food), true))).slice(0, 2);
}

const FIBER_GOAL = 25;

// 减脂目标进度
function computeGoal(data) {
  const g = data.goal;
  if (!g || !g.targetKg) return null;
  const durationDays = g.durationDays || 90;
  const targetKg = g.targetKg;
  const totalNeeded = targetKg * KCAL_PER_KG;
  const dailyTarget = Math.round(totalNeeded / durationDays);
  // 累积起点 = 历史中第一天有记录（没有记录则用设定的开始日期）
  const recordedKeys = Object.keys(data.days)
    .filter((k) => data.days[k].entries && data.days[k].entries.length)
    .sort();
  const start = recordedKeys.length ? recordedKeys[0] : (g.startDate || TODAY);
  const endDate = addDays(start, durationDays);
  const elapsed = Math.max(1, Math.min(durationDays, daysBetween(start, TODAY) + 1));
  const remainingDays = Math.max(0, durationDays - elapsed);
  let cumulative = 0, loggedDays = 0;
  for (const [k, day] of Object.entries(data.days)) {
    if (k >= start && k <= TODAY && day.entries && day.entries.length) {
      cumulative += deficitOf(day, data.profile.baseline);
      loggedDays++;
    }
  }
  const fatLost = cumulative / KCAL_PER_KG;
  const progressPct = totalNeeded > 0 ? Math.max(0, Math.min(1, cumulative / totalNeeded)) : 0;
  const expectedCumulative = dailyTarget * elapsed;
  const avgDaily = loggedDays > 0 ? cumulative / loggedDays : 0;
  const projectedKg = (avgDaily * durationDays) / KCAL_PER_KG;
  let pace = "start";
  if (loggedDays > 0) pace = cumulative >= expectedCumulative ? "ahead" : "behind";

  // 按目前节奏预计多久减完
  const remainingNeeded = Math.max(0, totalNeeded - cumulative);
  const reached = cumulative >= totalNeeded;
  let projTotalDays = null, projFinishDate = null;
  if (avgDaily > 0) {
    projTotalDays = totalNeeded / avgDaily;                 // 从开始算，达成目标共需天数
    projFinishDate = addDays(TODAY, Math.ceil(remainingNeeded / avgDaily));
  }

  // 今日缺口 vs 每日目标
  const todayDef = deficitOf(data.days[TODAY], data.profile.baseline);
  const todayVsTarget = todayDef === null ? null : todayDef - dailyTarget;

  return { targetKg, durationDays, start, endDate, dailyTarget, elapsed, remainingDays, cumulative, fatLost, progressPct, projectedKg, loggedDays, pace, avgDaily, projTotalDays, projFinishDate, reached, todayDef, todayVsTarget };
}

// 宏量状态文案（与 MacroBar 一致）
function macroStatus(value, goal, kind) {
  const pct = goal ? value / goal : 0;
  if (kind === "up") {
    if (pct >= 1) return { label: "达标", ok: true };
    if (pct >= 0.6) return { label: "接近", ok: false };
    return { label: "偏低", ok: false };
  }
  if (pct <= 1) return { label: "适量", ok: true };
  if (pct <= 1.3) return { label: "略多", ok: false };
  return { label: "偏高", ok: false };
}

// 单日营养点评（规则生成，即时、无 AI 等待）
function dayNutritionNote(day, profile, def, dailyTarget) {
  const tips = [];
  const p = profile.proteinGoal || 100;
  const f = profile.fiberGoal || FIBER_GOAL;
  if ((day.protein || 0) < p * 0.7) tips.push("蛋白偏低，可加鸡蛋 / 鱼 / 豆腐");
  if ((day.fiber || 0) < f * 0.6) tips.push("纤维不够，多加叶菜或全谷");
  if ((day.fat || 0) > (profile.fatGoal || 50)) {
    const c = topContributor(day, "fat");
    tips.push(c ? `脂肪略多，主要来自「${c.name}」` : "脂肪超出预算");
  }
  if ((day.carbs || 0) > (profile.carbGoal || 160)) {
    const c = topContributor(day, "carbs");
    tips.push(c ? `碳水略多，主要来自「${c.name}」` : "碳水超出预算");
  }
  const hasTrain = (day.entries || []).some((e) => (e.exercises || []).length);
  if (hasTrain && (day.protein || 0) < p * 0.8) tips.push("有训练但蛋白未达标，恢复会打折扣");
  if (profile.glucoseMode) {
    const stab = glucoseStability(day);
    if (stab?.level === "起伏较大") tips.push("升糖波动偏大，工作时段注意进食顺序");
    else if (stab?.level === "略有波动") tips.push("升糖略有波动，高糖餐可先菜后主食");
  }
  const caution = vitaminsOf(day).filter((v) => nutrientKind(v) === "caution");
  if (caution.some((v) => v.includes("糖") || v.includes("酒精"))) tips.push("有糖或酒精，留意下午专注力");
  if (tips.length) return tips.slice(0, 2).join("；");
  if (def != null && def >= dailyTarget) return "缺口与营养节奏都不错，继续保持";
  if (def != null && def > 0) return "有热量缺口，但别牺牲蛋白和纤维的质量";
  if (def != null && def <= 0) return "当天摄入 ≥ 消耗，明天可以回归节奏";
  return "记录完整，继续保持";
}

// 汇总一周营养数据
function analyzeWeekNutrition(weekDays, profile, dailyTarget) {
  const logged = weekDays.filter((x) => x.day && x.day.entries && x.day.entries.length);
  if (!logged.length) return null;
  const pG = profile.proteinGoal || 100;
  const fG = profile.fiberGoal || FIBER_GOAL;
  const cG = profile.carbGoal || 160;
  const fatG = profile.fatGoal || 50;

  let sumIntake = 0, sumProtein = 0, sumFiber = 0, sumCarbs = 0, sumFat = 0, sumBurn = 0;
  let proteinOk = 0, fiberOk = 0, goalOk = 0, trainDays = 0;
  const cautionFreq = {};
  const goodFreq = {};
  const dayDetails = [];

  logged.forEach(({ d, key, day, def }) => {
    sumIntake += day.intake || 0;
    sumProtein += day.protein || 0;
    sumFiber += day.fiber || 0;
    sumCarbs += day.carbs || 0;
    sumFat += day.fat || 0;
    sumBurn += day.burn || 0;
    if ((day.protein || 0) >= pG) proteinOk++;
    if ((day.fiber || 0) >= fG) fiberOk++;
    if (def != null && def >= dailyTarget) goalOk++;
    const exs = [];
    (day.entries || []).forEach((e) => (e.exercises || []).forEach((x) => exs.push(x.name)));
    if (exs.length) trainDays++;
    vitaminsOf(day).forEach((v) => {
      const bucket = nutrientKind(v) === "caution" ? cautionFreq : goodFreq;
      bucket[v] = (bucket[v] || 0) + 1;
    });
    const ps = macroStatus(day.protein || 0, pG, "up");
    const fs = macroStatus(day.fiber || 0, fG, "up");
    const cs = macroStatus(day.carbs || 0, cG, "budget");
    const fts = macroStatus(day.fat || 0, fatG, "budget");
    dayDetails.push({
      key,
      dow: WEEK[mondayIndex(d.getDay())],
      date: `${d.getMonth() + 1}/${d.getDate()}`,
      intake: day.intake || 0,
      def,
      protein: day.protein || 0,
      fiber: day.fiber || 0,
      carbs: day.carbs || 0,
      fat: day.fat || 0,
      macros: [
        { name: "蛋白", value: day.protein || 0, goal: pG, status: ps.label, ok: ps.ok },
        { name: "纤维", value: day.fiber || 0, goal: fG, status: fs.label, ok: fs.ok },
        { name: "碳水", value: day.carbs || 0, goal: cG, status: cs.label, ok: cs.ok },
        { name: "脂肪", value: day.fat || 0, goal: fatG, status: fts.label, ok: fts.ok },
      ],
      train: exs.length ? exs.slice(0, 3).join("、") + (exs.length > 3 ? "…" : "") : null,
      good: vitaminsOf(day).filter((v) => nutrientKind(v) === "good").slice(0, 5),
      caution: vitaminsOf(day).filter((v) => nutrientKind(v) === "caution").slice(0, 4),
      note: dayNutritionNote(day, profile, def, dailyTarget),
      isToday: key === TODAY,
    });
  });

  const n = logged.length;
  const avg = {
    intake: Math.round(sumIntake / n),
    protein: round2(sumProtein / n),
    fiber: round2(sumFiber / n),
    carbs: round2(sumCarbs / n),
    fat: round2(sumFat / n),
    burn: Math.round(sumBurn / n),
  };
  const topGood = Object.entries(goodFreq).sort((a, b) => b[1] - a[1]).slice(0, 5).map(([k]) => k);
  const topCaution = Object.entries(cautionFreq).sort((a, b) => b[1] - a[1]).slice(0, 4).map(([k]) => k);

  const insights = [];
  if (proteinOk < n * 0.5) insights.push(`蛋白仅 ${proteinOk}/${n} 天达标（目标 ${pG}g），训练周建议每餐都有优质蛋白`);
  else if (proteinOk === n) insights.push(`蛋白 ${n}/${n} 天都达标，保肌恢复基础很好`);
  if (fiberOk < n * 0.4) insights.push(`纤维多数天不足（${fiberOk}/${n} 天达标），饱腹感与肠道都受影响`);
  if (trainDays >= 2 && proteinOk < trainDays) insights.push(`${trainDays} 天有训练，但蛋白达标只有 ${proteinOk} 天——练后 30 分钟内补蛋白会更稳`);
  if (topCaution.length) insights.push(`本周常出现：${topCaution.join("、")}，留意总量与出现频次`);
  if (goalOk >= n * 0.7 && proteinOk >= n * 0.5) insights.push("热量缺口节奏和蛋白摄入整体协调，减脂质量较高");
  if (goalOk < n * 0.4 && n >= 3) insights.push("缺口达标天数偏少，可以检查是否有「大缺口 + 晚间补偿」的波动模式");

  return {
    loggedCount: n,
    proteinOk, fiberOk, goalOk, trainDays,
    avg,
    dayDetails,
    topGood,
    topCaution,
    insights: insights.slice(0, 4),
    avgMacros: [
      { label: "蛋白", value: avg.protein, goal: pG, kind: "up" },
      { label: "纤维", value: avg.fiber, goal: fG, kind: "up" },
      { label: "碳水", value: avg.carbs, goal: cG, kind: "budget" },
      { label: "脂肪", value: avg.fat, goal: fatG, kind: "budget" },
    ],
  };
}

// 当日营养均衡的简短提示（温和、以补充为主，不做严格限制）
function balanceHints({ intake, protein, fiber, fat, proteinGoal, fiberGoal }) {
  if (!intake) return null;
  const tips = [];
  if (protein < proteinGoal * 0.7) tips.push("蛋白偏低，加点鸡蛋 / 鱼 / 瘦肉 / 豆腐");
  if (fiber < fiberGoal * 0.6) tips.push("纤维还不够，多加蔬菜 / 全谷 / 豆类");
  const fatShare = (fat * 9) / intake;
  if (fatShare > 0.45) tips.push("脂肪占比偏高，下次可选瘦一点的部位");
  if (tips.length === 0) return { ok: true, text: "营养挺均衡，继续保持 💪" };
  return { ok: false, text: "可以再补一补：" + tips.slice(0, 2).join("；") };
}

// ── 经期 / 周期 ───────────────────────────────
function daysBetween(aKey, bKey) {
  const a = new Date(aKey + "T00:00:00");
  const b = new Date(bKey + "T00:00:00");
  return Math.round((b - a) / 86400000);
}
function addDays(key, n) {
  const d = new Date(key + "T00:00:00");
  d.setDate(d.getDate() + n);
  return iso(d);
}
function lastPeriodStart(periods, dateKey) {
  let last = null;
  for (const s of [...(periods || [])].sort()) {
    if (s <= dateKey) last = s; else break;
  }
  return last;
}
function isPeriodDay(dateKey, periods, profile) {
  const len = profile.periodLength || 5;
  return (periods || []).some((s) => {
    const d = daysBetween(s, dateKey);
    return d >= 0 && d < len;
  });
}
function cyclePhase(dateKey, periods, profile) {
  const start = lastPeriodStart(periods, dateKey);
  if (!start) return null;
  const cycleLen = profile.cycleLength || 28;
  const periodLen = profile.periodLength || 5;
  const cycleDay = daysBetween(start, dateKey) + 1;
  let phaseKey;
  if (cycleDay <= periodLen) phaseKey = "menstrual";
  else if (cycleDay <= 13) phaseKey = "follicular";
  else if (cycleDay <= 16) phaseKey = "ovulation";
  else phaseKey = "luteal";
  const nextStart = addDays(start, cycleLen);
  const daysToNext = daysBetween(dateKey, nextStart);
  return { phaseKey, cycleDay, cycleLen, periodLen, start, nextStart, daysToNext, late: cycleDay > cycleLen };
}

