// 营养细线条：label · 值/目标 · 进度
// kind='up'：越多越好（蛋白/纤维）；kind='budget'：别超标（碳水/脂肪）
function MacroBar({ label, value, goal, kind }) {
  const pct = goal ? value / goal : 0;
  const fill = Math.min(100, Math.round(pct * 100));
  let status, ideal;
  if (kind === "up") { ideal = pct >= 1; status = pct >= 1 ? "达标" : pct >= 0.6 ? "接近" : "偏低"; }
  else { ideal = pct <= 1; status = pct <= 1 ? "适量" : pct <= 1.3 ? "略多" : "偏高"; }
  return (
    <div style={S.macroRow}>
      <div style={S.macroTop}>
        <span style={S.macroLabel}>{label}</span>
        <span style={S.macroValWrap}>
          <span style={S.macroVal}>{round2(value)}</span>
          <span style={S.macroGoal}> / {goal}g</span>
          <span style={{ ...S.macroStatus, color: ideal ? C.accentDark : C.muted }}>{status}</span>
        </span>
      </div>
      <div style={S.macroTrack}>
        <div style={{ ...S.macroFill, width: `${fill}%` }} />
      </div>
    </div>
  );
}

function Entry({ e, onDelete, onItemDelete, onItemSave, reestimate }) {
  const kcal = (e.foods || []).reduce((s, f) => s + (f.kcal || 0), 0);
  const burn = (e.exercises || []).reduce((s, x) => s + (x.burn || 0), 0);
  return (
    <div style={S.entry}>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={S.entryTotal}>
          {kcal > 0 && <span>+{kcal} cal</span>}
          {burn > 0 && <span>运动 −{burn} cal</span>}
          <button className="link" style={S.entryDel} onClick={onDelete}>删除整条</button>
        </div>
        {(e.foods || []).map((f, i) => (
          <EntryItem
            key={"f" + i}
            item={f}
            type="food"
            onDelete={() => onItemDelete("food", i)}
            onSave={(patch) => onItemSave("food", i, patch)}
            reestimate={reestimate}
          />
        ))}
        {(e.exercises || []).map((x, i) => (
          <EntryItem
            key={"x" + i}
            item={x}
            type="exercise"
            onDelete={() => onItemDelete("exercise", i)}
            onSave={(patch) => onItemSave("exercise", i, patch)}
            reestimate={reestimate}
          />
        ))}
      </div>
    </div>
  );
}

function EntryItem({ item, type, onDelete, onSave, reestimate }) {
  const [editing, setEditing] = useState(false);
  const [f, setF] = useState(item);
  const [busy, setBusy] = useState(false);

  const open = () => { setF(item); setEditing(true); };
  const num = (v) => (v === "" || v === null || isNaN(+v) ? 0 : +v);
  const save = () => {
    if (type === "food") {
      onSave({ name: f.name, kcal: num(f.kcal), protein: num(f.protein), carbs: num(f.carbs), fat: num(f.fat), fiber: num(f.fiber), nutrients: f.nutrients || "", ...(f.time != null ? { time: f.time } : {}) });
    } else {
      onSave({ name: f.name, burn: num(f.burn), ...(f.time != null ? { time: f.time } : {}) });
    }
    setEditing(false);
  };
  const redetect = async () => {
    if (!f.name || !f.name.trim() || busy || !reestimate) return;
    setBusy(true);
    try {
      const patch = await reestimate(f.name, type);
      setF((cur) => ({ ...cur, ...patch }));
    } catch (e) { /* ignore */ }
    setBusy(false);
  };

  if (editing) {
    const fields = type === "food"
      ? [["kcal", "热量"], ["protein", "蛋白g"], ["carbs", "碳水g"], ["fat", "脂肪g"], ["fiber", "纤维g"]]
      : [["burn", "消耗 cal"]];
    return (
      <div style={S.itemEdit}>
        <div style={S.editNameRow}>
          <input
            className="field"
            style={{ ...S.editName, flex: 1 }}
            value={f.name}
            onChange={(e) => setF({ ...f, name: e.target.value })}
            placeholder="名称"
          />
          <button className="del" style={S.redetectBtn} onClick={redetect} disabled={busy}>
            {busy ? <span className="dots">估算</span> : "重新估算"}
          </button>
        </div>
        <div style={S.editGrid}>
          {fields.map(([k, label]) => (
            <div key={k} style={S.editField}>
              <label style={S.editLabel}>{label}</label>
              <input
                className="field"
                style={S.editNum}
                inputMode="numeric"
                value={f[k] ?? 0}
                onChange={(e) => setF({ ...f, [k]: e.target.value })}
              />
            </div>
          ))}
        </div>
        <div style={S.editTimeRow}>
          <label style={S.editLabel}>时间</label>
          <input
            className="field"
            style={{ ...S.editNum, width: 92, textAlign: "left" }}
            value={f.time || ""}
            onChange={(e) => setF({ ...f, time: e.target.value })}
            placeholder="HH:MM"
          />
          <span style={S.editTimeHint}>血糖曲线按此时间定位</span>
        </div>
        {type === "food" && (
          <input
            className="field"
            style={S.editName}
            value={f.nutrients || ""}
            onChange={(e) => setF({ ...f, nutrients: e.target.value })}
            placeholder="维生素/矿物质，如 维C、钾"
          />
        )}
        <div style={S.editActions}>
          <button className="send" style={S.editSave} onClick={save}>保存</button>
          <button className="del" style={S.editCancel} onClick={() => setEditing(false)}>取消</button>
          <button className="link" style={S.editDel} onClick={onDelete}>删除此项</button>
        </div>
      </div>
    );
  }

  const detail = type === "food"
    ? [
        `${item.kcal} cal`,
        `蛋白 ${item.protein}g`,
        item.carbs ? `碳水 ${item.carbs}g` : null,
        item.fat ? `脂肪 ${item.fat}g` : null,
        item.fiber ? `纤维 ${item.fiber}g` : null,
        item.gi != null && item.gi > 0 ? `升糖${glWord(foodGL(item))}` : null,
      ].filter(Boolean).join(" · ")
    : `−${item.burn} cal`;

  return (
    <div style={S.foodLine}>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={S.foodName}>{item.name}</div>
        <div style={S.foodMacros}>{detail}</div>
      </div>
      <button className="link" style={S.itemEditBtn} onClick={open}>编辑</button>
    </div>
  );
}

// ── 当日日志：饮食 / 训练 两个独立区域 ──────────────
function DayLog({ day, profile, onItemSave, onItemDelete, reestimate, analyze }) {
  const foods = [], exs = [];
  (day?.entries || []).forEach((e) => {
    (e.foods || []).forEach((f, i) => foods.push({ ts: e.ts, i, item: f }));
    (e.exercises || []).forEach((x, i) => exs.push({ ts: e.ts, i, item: x, text: e.text }));
  });
  const totalKcal = foods.reduce((s, o) => s + (o.item.kcal || 0), 0);
  const totalBurn = exs.reduce((s, o) => s + (o.item.burn || 0), 0);
  return (
    <>
      {foods.length > 0 && (
        <div style={S.card}>
          <div style={S.sectionHead}>
            <span style={S.sectionTitle}>饮食</span>
            <span style={S.sectionSum}>摄入 +{totalKcal} kcal</span>
          </div>
          {foods.map((o) => (
            <EntryItem
              key={o.ts + "f" + o.i}
              item={o.item}
              type="food"
              onSave={(patch) => onItemSave(o.ts, "food", o.i, patch)}
              onDelete={() => onItemDelete(o.ts, "food", o.i)}
              reestimate={reestimate}
            />
          ))}
        </div>
      )}
      {exs.length > 0 && (
        <div style={S.card}>
          <div style={S.sectionHead}>
            <span style={S.sectionTitle}>训练</span>
            <span style={S.sectionSum}>消耗 −{totalBurn} kcal</span>
          </div>
          {exs.map((o) => (
            <EntryItem
              key={o.ts + "x" + o.i}
              item={o.item}
              type="exercise"
              onSave={(patch) => onItemSave(o.ts, "exercise", o.i, patch)}
              onDelete={() => onItemDelete(o.ts, "exercise", o.i)}
              reestimate={reestimate}
            />
          ))}
          <TrainingAnalysis exs={exs} analyze={analyze} profile={profile} />
        </div>
      )}
    </>
  );
}

function TrainingAnalysis({ exs, analyze, profile }) {
  const [res, setRes] = useState(null);
  const [busy, setBusy] = useState(false);
  const [open, setOpen] = useState(false);
  // 与全局一致的 EPOC 估算（力量 0.12 / 球类 0.10 / 有氧 0.06 / 其他 0.07）
  const epoc = Math.round((exs || []).reduce((s, o) => {
    const x = o.item || o;
    const k = exKind(x);
    const f = k === "strength" ? 0.12 : k === "sport" ? 0.10 : k === "cardio" ? 0.06 : 0.07;
    return s + (x.burn || 0) * f;
  }, 0));
  const run = async () => {
    if (busy) return;
    setBusy(true);
    try { setRes(await analyze(exs, profile)); } catch (e) { /* ignore */ }
    setBusy(false);
  };
  if (!res) {
    return (
      <button className="send" style={S.analyzeBtn} onClick={run} disabled={busy}>
        {busy ? <span className="dots">分析训练</span> : "智能训练分析"}
      </button>
    );
  }
  return (
    <div style={S.report}>
      {/* 1 · 一句话结论：今天干得棒 */}
      <div style={S.verdictBox}>
        <div style={S.verdictTop}>
          {res.rating && <span style={S.verdictTag}>{res.rating}</span>}
          {res.focus && <span style={S.verdictFocus}>主练 · {res.focus}</span>}
        </div>
        {res.verdict && <div style={S.verdictText}>{res.verdict}</div>}
      </div>

      {/* 2 · 肌肉图：今日激活的肌群 */}
      {Array.isArray(res.trained) && res.trained.length > 0 && (
        <div style={S.mapWrap}>
          <MuscleMap trained={res.trained} />
          <div style={S.muscleChips}>
            {res.trained.filter((k) => MUSCLE_CN[k]).map((k) => (
              <span key={k} style={S.muscleChip}>{MUSCLE_CN[k]}</span>
            ))}
          </div>
          <div style={S.mapCap}>绿色为今日激活的肌群</div>
        </div>
      )}

      {/* 3 · 下次怎么做：高亮单条 */}
      {res.next && (
        <div style={S.nextBox}>
          <div style={S.nextLabel}>下次怎么做</div>
          <div style={S.nextText}>{res.next}</div>
        </div>
      )}

      {epoc > 0 && (
        <div style={S.epocNote}>
          力量训练带来约 <b style={{ color: C.accentDark }}>{epoc} kcal</b> 的运动后持续消耗（afterburn），已计入当天消耗与缺口。
        </div>
      )}

      {/* 4 · 详细分析：默认折叠，避免信息过载 */}
      <button className="link" style={S.detailToggle} onClick={() => setOpen(!open)}>
        {open ? "收起详细分析 ▲" : "查看详细分析 ▾"}
      </button>
      {open && (
        <div style={S.detailWrap}>
          {(res.groups || []).map((g, i) => (
            <div key={i} style={S.repGroup}>
              <div style={S.repGroupTop}>
                <span style={S.repGroupName}>{g.name}</span>
                {g.sets > 0 && <span style={S.repSets}>{g.sets} 组</span>}
              </div>
              {Array.isArray(g.muscles) && g.muscles.length > 0 && (
                <div style={S.repMuscles}>
                  {g.muscles.map((m, j) => <span key={j} style={S.muscleTag}>{m}</span>)}
                </div>
              )}
              {g.note && <div style={S.repNote}>{g.note}</div>}
            </div>
          ))}
          {res.scheme && <div style={S.repBlock}><b style={S.repB}>强度</b>{res.scheme}</div>}
          {res.balance && <div style={S.repBlock}><b style={S.repB}>均衡</b>{res.balance}</div>}
          {res.principle && <div style={S.repPrinciple}>{res.principle}</div>}
          {Array.isArray(res.tips) && res.tips.length > 0 && (
            <ul style={S.repTips}>
              {res.tips.map((t, i) => <li key={i} style={S.repTip}><span style={S.repTipDot} />{t}</li>)}
            </ul>
          )}
        </div>
      )}
      <button className="link" style={S.refreshBtn} onClick={run} disabled={busy}>
        {busy ? "重新分析…" : "重新分析"}
      </button>
    </div>
  );
}

