// ── 月历（信号元素）──────────────────────────────
function Calendar({ data, calMonth, setCalMonth, picked, setPicked }) {
  const { y, m } = calMonth;
  const first = new Date(y, m, 1);
  const offset = mondayIndex(first.getDay());
  const daysInMonth = new Date(y, m + 1, 0).getDate();
  const cells = [];
  for (let i = 0; i < offset; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  const move = (delta) => {
    let nm = m + delta, ny = y;
    if (nm < 0) { nm = 11; ny--; } if (nm > 11) { nm = 0; ny++; }
    setCalMonth({ y: ny, m: nm });
  };

  return (
    <div style={S.card}>
      <div style={S.calHead}>
        <button className="nav" style={S.nav} onClick={() => move(-1)}>‹</button>
        <div style={S.calTitle}>{y} 年 {m + 1} 月</div>
        <button className="nav" style={S.nav} onClick={() => move(1)}>›</button>
      </div>
      <div style={S.grid}>
        {WEEK.map((w) => (
          <div key={w} style={S.weekCell}>{w}</div>
        ))}
        {cells.map((d, i) => {
          if (d === null) return <div key={i} />;
          const key = `${y}-${String(m + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
          const def = deficitOf(data.days[key], data.profile.baseline);
          const isToday = key === TODAY;
          const isPicked = key === picked;
          const period = isPeriodDay(key, data.periods, data.profile);
          return (
            <button key={i} className="dayCell" style={S.dayCell} onClick={() => setPicked(key)}>
              <span
                style={{
                  ...S.dayBlock,
                  background: isPicked ? C.ink : "transparent",
                  boxShadow: isToday && !isPicked ? `inset 0 0 0 1.5px ${C.ink}` : "none",
                }}
              >
                <span style={{ ...S.dayNum2, color: isPicked ? "#FFFFFF" : C.ink }}>{d}</span>
                <span style={{ ...S.dayCal, color: isPicked ? "rgba(255,255,255,.82)" : def === null ? "transparent" : def >= 300 ? C.accentDark : C.muted }}>
                  {def === null ? "" : `${def > 0 ? "−" : def < 0 ? "+" : ""}${Math.abs(def)}`}
                </span>
                {period && <span style={S.periodCorner} />}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

function WeekView({ data, weekOffset, setWeekOffset, picked, setPicked }) {
  // 以今天所在的周一为基准，按 weekOffset 周偏移
  const base = new Date();
  base.setDate(base.getDate() - mondayIndex(base.getDay()) + weekOffset * 7);
  const days = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date(base);
    d.setDate(base.getDate() + i);
    const key = iso(d);
    const day = data.days[key];
    const def = deficitOf(day, data.profile.baseline);
    days.push({ d, key, day, def });
  }
  const logged = days.filter((x) => x.day && x.day.entries.length);
  const weekTotal = logged.reduce((s, x) => s + x.def, 0);
  const start = days[0].d, end = days[6].d;
  const range = `${start.getMonth() + 1}/${start.getDate()} – ${end.getMonth() + 1}/${end.getDate()}`;

  // 本周 vs 目标
  const dailyTarget = data.goal && data.goal.durationDays
    ? Math.round((data.goal.targetKg * KCAL_PER_KG) / data.goal.durationDays)
    : 300;
  const weeklyTarget = dailyTarget * 7;
  const pct = weeklyTarget ? Math.round((weekTotal / weeklyTarget) * 100) : 0;
  // 轻量点图几何：维持线为 0，目标线为 dailyTarget，吃超→基线下方红点
  const defsScale = days.map((x) => (x.def == null ? 0 : x.def));
  const cvmax = Math.max(dailyTarget * 1.2, ...defsScale, 1);
  const cvmin = Math.min(0, ...defsScale);
  const cspan = (cvmax - cvmin) || 1;
  const chTop = 10, chH = 48, colW = 300 / 7;
  const yOf = (v) => chTop + ((cvmax - v) / cspan) * chH;
  const yZero = yOf(0), yTarget = yOf(dailyTarget);
  const pts = days.map((x, i) => {
    const has = x.def != null;
    const def = has ? x.def : 0;
    const color = !has ? C.faint : def >= dailyTarget ? C.accent : def > 0 ? "#D6A95E" : "#D08A7A";
    return { cx: colW * (i + 0.5), y: yOf(def), color, has, today: x.key === TODAY, lab: WEEK[i] };
  });
  const weekNut = analyzeWeekNutrition(days, data.profile, dailyTarget);

  return (
    <>
    <div style={S.card}>
      <div style={S.calHead}>
        <button className="nav" style={S.nav} onClick={() => setWeekOffset(weekOffset - 1)}>‹</button>
        <div style={S.calTitle}>{weekOffset === 0 ? "本周" : range}</div>
        <button className="nav" style={S.nav} onClick={() => setWeekOffset(weekOffset + 1)}>›</button>
      </div>

      <div style={S.weekRow}>
        {days.map(({ d, key, def }) => {
          const isToday = key === TODAY;
          const isPicked = key === picked;
          const period = isPeriodDay(key, data.periods, data.profile);
          return (
            <button key={key} className="dayCell" style={S.weekCellBtn} onClick={() => setPicked(key)}>
              <span style={S.weekDow}>{WEEK[mondayIndex(d.getDay())]}</span>
              <span
                style={{
                  ...S.dayBlock,
                  background: isPicked ? C.ink : "transparent",
                  boxShadow: isToday && !isPicked ? `inset 0 0 0 1.5px ${C.ink}` : "none",
                }}
              >
                <span style={{ ...S.dayNum2, color: isPicked ? "#FFFFFF" : C.ink }}>{d.getDate()}</span>
                <span style={{ ...S.dayCal, color: isPicked ? "rgba(255,255,255,.82)" : def === null ? "transparent" : def >= dailyTarget ? C.accentDark : C.muted }}>
                  {def === null ? "" : `${def > 0 ? "−" : def < 0 ? "+" : ""}${Math.abs(def)}`}
                </span>
                {period && <span style={S.periodCorner} />}
              </span>
            </button>
          );
        })}
      </div>

      <div style={S.weekSummary}>
        <div>
          <div style={S.weekSumLabel}>本周总热量盈亏</div>
          <div style={S.weekSumSub}>已记录 {logged.length}/7 天</div>
        </div>
        <div style={S.weekSumVal}>
          {weekTotal > 0 ? "−" : weekTotal < 0 ? "+" : ""}{Math.abs(weekTotal)}
          <span style={S.weekSumUnit}> kcal</span>
        </div>
      </div>
      {logged.length > 0 && (
        <div style={S.weekAvg}>
          日均{weekTotal >= 0 ? "缺口" : "盈余"} {Math.round(Math.abs(weekTotal) / logged.length)} kcal
          {weekTotal > 0 && ` · 本周累计约减脂 ${(weekTotal / 7700).toFixed(2)} kg`}
        </div>
      )}

      {/* 本周 vs 减脂目标 */}
      <div style={S.weekGoal}>
        <div style={S.weekGoalHead}>
          <span style={S.weekGoalTitle}>本周 vs 目标</span>
          <span style={{ ...S.weekGoalPct, color: pct >= 100 ? C.accentDark : C.muted }}>
            {pct}%{pct >= 100 ? " ✦" : ""}
          </span>
        </div>
        <div style={S.goalTrack}>
          <div style={{ ...S.goalFill, width: `${Math.max(0, Math.min(100, pct))}%`, background: pct >= 100 ? C.accentDark : C.accent }} />
        </div>
        <div style={S.weekGoalSub}>
          累计缺口 {Math.max(0, weekTotal)} / 计划 {weeklyTarget} kcal
          {pct >= 100
            ? <b style={{ color: C.accentDark }}>　·　超预期 {pct - 100}%</b>
            : `　·　还差 ${Math.max(0, weeklyTarget - weekTotal)}`}
        </div>
        <svg viewBox="0 0 300 80" width="100%" style={{ display: "block", marginTop: 10 }}>
          <line x1="0" y1={yZero} x2="300" y2={yZero} stroke={C.line} strokeWidth="1" />
          <text x="2" y={yZero - 4} fontSize="8" fill={C.faint} fontFamily="Inter">维持</text>
          <line x1="0" y1={yTarget} x2="300" y2={yTarget} stroke={C.accent} strokeWidth="1" strokeDasharray="4 3" opacity="0.7" />
          <text x="298" y={yTarget - 4} textAnchor="end" fontSize="8" fill={C.accentDark} fontFamily="Inter">日标 {dailyTarget}</text>
          {pts.map((p, i) => (
            <g key={i}>
              {p.has && <line x1={p.cx} y1={yZero} x2={p.cx} y2={p.y} stroke={p.color} strokeWidth="1.5" />}
              <circle cx={p.cx} cy={p.has ? p.y : yZero} r={p.has ? 3.4 : 2.4} fill={p.has ? p.color : "#fff"} stroke={p.has ? "none" : C.line} />
              <text x={p.cx} y="76" textAnchor="middle" fontSize="9.5" fill={p.today ? C.accentDark : C.faint} fontFamily="Inter" fontWeight={p.today ? 700 : 400}>{p.lab}</text>
            </g>
          ))}
        </svg>
        <div style={S.weekGoalLegend}>点=当天净缺口：<b style={{ color: C.accentDark }}>绿达标</b> · 黄未达标 · 红盈余（吃超），虚线=每日目标</div>
      </div>
    </div>

    {weekNut && (
      <WeekNutritionPanel analysis={weekNut} onPick={setPicked} />
    )}
    </>
  );
}

