function Style() {
  return (
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;600;700&family=Inter:wght@400;500;600;700&family=Noto+Serif+SC:wght@500;600;700&display=swap');
      * { box-sizing: border-box; }
      body { margin: 0; }
      ::selection { background: ${C.ink}; color: ${C.bg}; }
      .tab { transition: color .15s; }
      .tab:hover { color: ${C.ink}; }
      .send { transition: opacity .15s; }
      .send:hover { opacity: .82; }
      .send:disabled { opacity: .4; cursor: default; }
      .nav:hover, .del:hover { border-color: ${C.ink}; color: ${C.ink}; }
      .dayCell { transition: transform .12s; }
      .dayCell:hover { transform: scale(1.05); }
      .field:focus { border-color: ${C.ink} !important; }
      .link:hover { opacity: .6; }
      .phaseBanner:hover { background: ${C.soft}; }
      .dots::after { content: '…'; animation: blink 1.2s infinite; }
      @keyframes blink { 0%,100%{opacity:.3} 50%{opacity:1} }
      @media (prefers-reduced-motion: reduce) { * { animation: none !important; transition: none !important; } }
    `}</style>
  );
}
